from fastapi import FastAPI, Depends, HTTPException, status
from enum import Enum
from typing import Annotated

class Role(str, Enum):
    ADMIN = "admin"
    EDITOR = "editor"
    VIEWER = "viewer"

# Auth dependency (returns user with role)
async def get_current_user(token: str = Depends(oauth2_scheme)):
    user = decode_token(token)  # returns {"id": 1, "role": "admin"}
    if not user:
        raise HTTPException(status_code=401, detail="Invalid credentials")
    return user

# Authorization dependency factory
def require_role(*roles: Role):
    async def check_role(user: dict = Depends(get_current_user)):
        if user["role"] not in [r.value for r in roles]:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Role {user['role']} not authorized"
            )
        return user
    return check_role

app = FastAPI()

@app.delete("/users/{user_id}")
async def delete_user(
    user_id: int,
    user: dict = Depends(require_role(Role.ADMIN))
):
    return {"deleted": user_id}

@app.put("/posts/{post_id}")
async def edit_post(
    post_id: int,
    user: dict = Depends(require_role(Role.ADMIN, Role.EDITOR))
):
    return {"edited": post_id}

import strawberry
from fastapi import FastAPI
from strawberry.fastapi import GraphQLRouter
from typing import List

@strawberry.type
class User:
    id: int
    name: str
    email: str

users_db = [
    User(id=1, name="Alice", email="alice@example.com"),
    User(id=2, name="Bob", email="bob@example.com"),
]

@strawberry.type
class Query:
    @strawberry.field
    def users(self) -> List[User]:
        return users_db

    @strawberry.field
    def user(self, id: int) -> User | None:
        return next((u for u in users_db if u.id == id), None)

@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_user(self, name: str, email: str) -> User:
        user = User(id=len(users_db) + 1, name=name, email=email)
        users_db.append(user)
        return user

schema = strawberry.Schema(query=Query, mutation=Mutation)
graphql_app = GraphQLRouter(schema)

app = FastAPI()
app.include_router(graphql_app, prefix="/graphql")
# GraphiQL IDE available at /graphql

